import{_ as e,b as o,o as r,i as c,j as a,g as n,aB as i}from"./chunks/framework._ZAOES46.js";const u=JSON.parse('{"title":"FaAnimatedBeam 动画光束","description":"","frontmatter":{},"headers":[],"relativePath":"components/pro/FaAnimatedBeam.md","filePath":"components/pro/FaAnimatedBeam.md"}'),s={name:"components/pro/FaAnimatedBeam.md"};function l(m,t,p,h,f,g){const d=o("Badge");return r(),c("div",null,[t[0]||(t[0]=a("div",{style:{display:"none"},hidden:"true","aria-hidden":"true","data-nosnippet":""},"Are you an LLM? You can read better optimized documentation at /components/pro/FaAnimatedBeam.md for this page in Markdown format",-1)),n(d,{type:"pro",text:"专业版"}),t[1]||(t[1]=i('<h1 id="faanimatedbeam-动画光束" tabindex="-1">FaAnimatedBeam 动画光束 <a class="header-anchor" href="#faanimatedbeam-动画光束" aria-label="Permalink to “FaAnimatedBeam 动画光束”">​</a></h1><p>动态光束连接组件，用于在两个元素之间创建流动的动画光束效果，适合展示元素之间的关联关系。</p><h2 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h2><ul><li>技术栈关联展示</li><li>数据流向可视化</li><li>架构图连接关系</li><li>功能模块关联图</li><li>思维导图连接线</li></ul><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to “Props”">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>类型</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>containerRef</code></td><td><code>HTMLElement | null</code></td><td><strong>必需</strong></td><td>容器元素引用</td></tr><tr><td><code>fromRef</code></td><td><code>HTMLElement | null</code></td><td><strong>必需</strong></td><td>起点元素引用</td></tr><tr><td><code>toRef</code></td><td><code>HTMLElement | null</code></td><td><strong>必需</strong></td><td>终点元素引用</td></tr><tr><td><code>curvature</code></td><td><code>number</code></td><td><code>0</code></td><td>光束曲率（弧度）</td></tr><tr><td><code>reverse</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否反向动画</td></tr><tr><td><code>pathColor</code></td><td><code>string</code></td><td><code>&#39;gray&#39;</code></td><td>路径颜色</td></tr><tr><td><code>pathWidth</code></td><td><code>number</code></td><td><code>2</code></td><td>路径宽度</td></tr><tr><td><code>pathOpacity</code></td><td><code>number</code></td><td><code>0.2</code></td><td>路径透明度</td></tr><tr><td><code>dotted</code></td><td><code>boolean</code></td><td><code>false</code></td><td>是否虚线样式</td></tr><tr><td><code>dotSpacing</code></td><td><code>number</code></td><td><code>6</code></td><td>虚线点间距</td></tr><tr><td><code>gradientStartColor</code></td><td><code>string</code></td><td><code>&#39;#FFAA40&#39;</code></td><td>渐变起始色</td></tr><tr><td><code>gradientStopColor</code></td><td><code>string</code></td><td><code>&#39;#9C40FF&#39;</code></td><td>渐变终止色</td></tr><tr><td><code>delay</code></td><td><code>number</code></td><td><code>0</code></td><td>动画延迟（秒）</td></tr><tr><td><code>duration</code></td><td><code>number</code></td><td><code>4-7</code></td><td>动画持续时间（秒）</td></tr><tr><td><code>startXOffset</code></td><td><code>number</code></td><td><code>0</code></td><td>起点 X 偏移</td></tr><tr><td><code>startYOffset</code></td><td><code>number</code></td><td><code>0</code></td><td>起点 Y 偏移</td></tr><tr><td><code>endXOffset</code></td><td><code>number</code></td><td><code>0</code></td><td>终点 X 偏移</td></tr><tr><td><code>endYOffset</code></td><td><code>number</code></td><td><code>0</code></td><td>终点 Y 偏移</td></tr><tr><td><code>class</code></td><td><code>HTMLAttributes[&#39;class&#39;]</code></td><td>-</td><td>自定义 CSS 类</td></tr></tbody></table><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to “注意事项”">​</a></h2><ol><li><strong>必需引用</strong>：<code>containerRef</code>、<code>fromRef</code>、<code>toRef</code> 都是必需的，需要使用 <code>useTemplateRef</code> 获取 DOM 引用</li><li><strong>容器定位</strong>：容器元素必须设置为 <code>relative</code> 定位，光束使用绝对定位</li><li><strong>响应式更新</strong>：组件会自动监听容器和元素位置变化，自动更新路径</li><li><strong>动画方向</strong>：组件会自动检测光束方向（水平/垂直）并调整动画方向</li><li><strong>性能优化</strong>：使用 ResizeObserver 监听容器大小变化，避免频繁重绘</li><li><strong>Z 轴层级</strong>：光束元素使用 <code>pointer-events-none</code>，不会影响鼠标事件</li><li><strong>曲率效果</strong>：正曲率向下弯曲，负曲率向上弯曲</li></ol>',8))])}const _=e(s,[["render",l]]);export{u as __pageData,_ as default};
